<script setup>
import {computed, inject} from "vue";
import {ColumnTypeNumber} from "@/DataGrid/js/Column/ColumnType/ColumnTypeNumber";
import {useTranslations} from "@/Composables/useTranslation.js";
import {ColumnTypeText} from "@/DataGrid/js/Column/ColumnType/ColumnTypeText";
import {ColumnTypeBool} from "@/DataGrid/js/Column/ColumnType/ColumnTypeBool";
import {ColumnTypeDate} from "@/DataGrid/js/Column/ColumnType/ColumnTypeDate";
import {ColumnTypeDateTime} from "@/DataGrid/js/Column/ColumnType/ColumnTypeDateTime";
import {ColumnTypeEnum} from "@/DataGrid/js/Column/ColumnType/ColumnTypeEnum";
import {ColumnTypeCurrency} from "@/DataGrid/js/Column/ColumnType/ColumnTypeCurrency";
import DatePicker from "@/Components/Inputs/DatePicker.vue";

const dataGridState = inject('dataGridState', null);
const grid = dataGridState.grid;
const state = dataGridState.filterDialog;

const {translations} = useTranslations();

//TODO předělat z grid.ajax.state na object a pak řešit v data() dataGridu
const applyFilter = () => {
    if(grid.ajax){
        Object.entries(state.data).forEach(([key, value]) => {
           if(typeof value === "object" && value !== null){
               if(Array.isArray(value)){
                   grid.ajax.state[key] = value;
                   return;
               }


               if(typeof value.from !== 'undefined' && value.from !== null && value.from !== ''){
                   grid.ajax.state[key + 'From'] = value.from;
               }else{
                   delete grid.ajax.state[key + 'From'];
               }

               if(typeof value.to !== 'undefined' && value.to !== null && value.to !== ''){
                   grid.ajax.state[key + 'To'] = value.to;
               }else{
                   delete grid.ajax.state[key + 'To'];
               }

               if(grid.ajax.state[key + 'From'] || grid.ajax.state[key + 'To']){
                   grid.ajax.state[key] = (grid.ajax.state[key + 'From'] ?? '') + ':' + (grid.ajax.state[key + 'To'] ?? '');
               }else{
                   delete grid.ajax.state[key];
               }
           }else{
               if(typeof value !== 'undefined' && value !== null && value !== ''){
                   grid.ajax.state[key] = value;
               }else{
                   delete grid.ajax.state[key];
               }
           }
        });

        grid.ajax.reload(null, true);
    }

    state.show = false;
}

const rangeValue = computed(() => (key) => {
    if (!state.data[key]) {
        state.data[key] = { from: null, to: null };
    }
    return state.data[key];
});

const resetFilter = () => {
    Object.entries(state.data).forEach(([key, value]) => {
        state.data[key] = null;
    });
}
</script>

<template>
    <Modal
        :is-visible="state.show"
        @close="state.show = false"
    >
        <template #header>

        </template>
        <template #body>
            <Form :state="state">
                <div class="row">
                    <template v-for="column in grid.columns">
                        <div class="col-12 md:col-6" v-if="column.external?.filter">
                            <template v-if="column.format instanceof ColumnTypeBool">
                                <RadioBool
                                    :label="column.label"
                                    v-model="state.data[column.data]"
                                    :none-option="true"
                                    direction="inline"
                                />
                            </template>
                            <template v-if="column.format instanceof ColumnTypeDate">
                                <DatePicker
                                    :label="column.label"
                                    v-model="state.data[column.data]"
                                    :range="true"
                                    type="date"
                                />
                            </template>
                            <template v-if="column.format instanceof ColumnTypeDateTime">
                                <DatePicker
                                    :label="column.label"
                                    v-model="state.data[column.data]"
                                    :range="true"
                                    type="datetime"
                                />
                            </template>
                            <template v-if="column.format instanceof ColumnTypeEnum">
                                <Select
                                    :label="column.label"
                                    v-model="state.data[column.data]"
                                    :multiple="true"
                                    :options="column.enumValues ? Object.entries(column.enumValues).map(([key, value]) => ({
                                      text: value,
                                      value: isNaN(key) ? key : Number(key)
                                    })) : []"
                                />
                            </template>
                            <template v-if="column.format instanceof ColumnTypeNumber">
                                <div class="number-range">
                                    <InputField
                                        :label="column.label + ' ' + translations.FROM"
                                        v-model="rangeValue(column.data).from"
                                        type="number"
                                        class="from"
                                    />
                                    <InputField
                                        :label="column.label + ' ' + translations.TO"
                                        v-model="rangeValue(column.data).to"
                                        type="number"
                                        class="to"
                                    />
                                </div>
                            </template>
                            <template v-if="column.format instanceof ColumnTypeText">
                                <InputField
                                    :label="column.label"
                                    v-model="state.data[column.data]"
                                    type="text"
                                />
                            </template>
                          <template v-if="column.format instanceof ColumnTypeCurrency">
                            <InputField
                              :label="column.label"
                              v-model="state.data[column.data]"
                              type="currency"
                            />
                          </template>
                        </div>
                    </template>
                    <slot :data="state.data"></slot>
                </div>
            </Form>
        </template>
        <template #footer>
            <Button
                variant="green"
                @click="applyFilter"
                class="mr-2"
            >
                Potvrdit
            </Button>
            <Button
                variant="orange"
                @click="resetFilter"
                class="mr-2"
            >
                Resetovat
            </Button>
            <Button
                variant="red"
                @click="state.show = false"
                class="mr-2"
            >
                Zavřít
            </Button>
        </template>
    </Modal>
</template>

<style scoped>
.number-range{
    display: flex;
    gap: 30px;

    .from, .to{
        flex-grow: 1;
    }
}
</style>